#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
setup_presparc_skill.py
=======================
Script de création complète du skill presparc-notion pour Agent Zero.
Présence-Parcours v2.0 — 2026-03-01

Usage:
    python setup_presparc_skill.py                         # Créer dans ./presparc-notion/
    python setup_presparc_skill.py --target /a0/usr/skills/presparc-notion
    python setup_presparc_skill.py --target ./presparc-notion --dry-run
    python setup_presparc_skill.py --target ./presparc-notion --force   # Écraser les existants

Ce script est AUTONOME et IDEMPOTENT.
Il crée ~18 fichiers répartis dans 6 dossiers.
Aucune dépendance externe requise (stdlib Python uniquement).
"""

import argparse
import os
import sys
from pathlib import Path

# ─── Couleurs ANSI ────────────────────────────────────────────────────────────
_IS_TTY = sys.stdout.isatty()
def _c(code, text): return f"\033[{code}m{text}\033[0m" if _IS_TTY else text
OK   = lambda t: print(f"  {_c('92','✓')} {t}")
ERR  = lambda t: print(f"  {_c('91','✗')} {t}", file=sys.stderr)
WARN = lambda t: print(f"  {_c('93','⚠')} {t}")
INFO = lambda t: print(f"  {_c('96','→')} {t}")
HEAD = lambda t: print(f"\n{_c('1;96', t)}")

# ══════════════════════════════════════════════════════════════════════════════
#  CONTENU DE CHAQUE FICHIER
# ══════════════════════════════════════════════════════════════════════════════

FILES: dict[str, str] = {}

# ─── requirements.txt ────────────────────────────────────────────────────────
import base64 as _b64
_ENCODED_FILES: dict[str, str] = {}
_ENCODED_FILES["requirements.txt"] = "bm90aW9uLWNsaWVudD49Mi4yLjEKcmVxdWVzdHM+PTIuMzEuMApweXRob24tZG90ZW52Pj0xLjAuMApQeVlBTUw+PTYuMApyaWNoPj0xMy4wLjA="
_ENCODED_FILES[".env.example"] = ""
_ENCODED_FILES[".gitignore"] = "LmVudgoqLnB5YwpfX3B5Y2FjaGVfXy8Kb3V0cHV0LwoqLmxvZwouRFNfU3RvcmU="
_ENCODED_FILES["SKILL.md"] = ""
_ENCODED_FILES["config/databases.json"] = ""
_ENCODED_FILES["utils/__init__.py"] = "IyB1dGlscyBwYWNrYWdlIOKAlCBwcmVzcGFyYy1ub3Rpb24="
_ENCODED_FILES["utils/logger.py"] = ""
_ENCODED_FILES["utils/validators.py"] = ""
_ENCODED_FILES["utils/notion_api.py"] = ""
_ENCODED_FILES["scripts/check_portal_integrity.py"] = ""
_ENCODED_FILES["scripts/generate_monthly_report.py"] = ""
_ENCODED_FILES["scripts/enrich_objectifs_comptes_rendus.py"] = ""
_ENCODED_FILES[".a0_docs/scheduler_tasks.json"] = ""
_ENCODED_FILES[".a0_docs/a0_behaviour_rules.json"] = ""
_ENCODED_FILES[".a0_docs/memory_init.json"] = ""
_ENCODED_FILES[".a0_docs/DEPLOYMENT_GUIDE.md"] = ""

FILES: dict[str, str] = {k: _b64.b64decode(v).decode('utf-8') for k, v in _ENCODED_FILES.items()}


# ══════════════════════════════════════════════════════════════════════════════
#  MOTEUR DE CRÉATION
# ══════════════════════════════════════════════════════════════════════════════

def write_file(path: Path, content: str, dry_run: bool, force: bool) -> str:
    """
    Écrit un fichier. Retourne 'created', 'updated', 'skipped' ou 'error'.
    """
    if path.exists() and not force:
        return "skipped"
    action = "updated" if path.exists() else "created"
    if not dry_run:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
    return action


def run(target: Path, dry_run: bool, force: bool) -> None:
    HEAD(f"{'[DRY-RUN] ' if dry_run else ''}Création du skill presparc-notion")
    print(f"  Destination : {target.resolve()}")

    counts = {"created": 0, "updated": 0, "skipped": 0, "error": 0}

    for rel_path, content in FILES.items():
        dest    = target / rel_path
        action  = write_file(dest, content, dry_run, force)
        counts[action] += 1
        icon = {"created": "✓", "updated": "↺", "skipped": "–", "error": "✗"}[action]
        color = {"created": "92", "updated": "93", "skipped": "90", "error": "91"}[action]
        if _IS_TTY:
            print(f"  {_c(color, icon)} {rel_path}")
        else:
            print(f"  {icon} {rel_path}")

    # Créer les dossiers vides
    for empty_dir in ("output", "scripts"):
        d = target / empty_dir
        if not dry_run:
            d.mkdir(parents=True, exist_ok=True)

    HEAD("Résumé")
    print(f"  Créés    : {counts['created']}")
    print(f"  Mis à jour: {counts['updated']}")
    print(f"  Ignorés  : {counts['skipped']}  (utilisez --force pour écraser)")
    print(f"  Erreurs  : {counts['error']}")

    if dry_run:
        WARN("Simulation terminée — aucun fichier écrit (--dry-run)")
        return

    HEAD("Étapes suivantes")
    steps = [
        f"cd {target}",
        "cp .env.example .env  &&  nano .env   # Renseigner NOTION_TOKEN",
        "pip install -r requirements.txt",
        "python scripts/check_portal_integrity.py --json-only  # Test",
        "# Copier vers Agent Zero :",
        f"cp -r {target} ~/a0-data/skills/presparc-notion",
        "# Puis configurer secrets, behaviour_rules et scheduler dans Agent Zero",
    ]
    for i, s in enumerate(steps, 1):
        print(f"  {i}. {s}")
    print()


# ══════════════════════════════════════════════════════════════════════════════
#  POINT D'ENTRÉE
# ══════════════════════════════════════════════════════════════════════════════

def main() -> None:
    parser = argparse.ArgumentParser(
        description="Crée tous les fichiers du skill presparc-notion",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=__doc__,
    )
    parser.add_argument(
        "--target", "-t",
        type=Path, default=Path("./presparc-notion"),
        help="Dossier de destination (défaut : ./presparc-notion)",
    )
    parser.add_argument(
        "--dry-run", action="store_true",
        help="Afficher les fichiers qui seraient créés sans écrire",
    )
    parser.add_argument(
        "--force", "-f", action="store_true",
        help="Écraser les fichiers existants",
    )
    parser.add_argument(
        "--list", action="store_true",
        help="Lister les fichiers inclus et quitter",
    )
    args = parser.parse_args()

    if args.list:
        print(f"Fichiers inclus ({len(FILES)}) :")
        for f in sorted(FILES):
            size = len(FILES[f].encode())
            print(f"  {f:55s}  {size:>6} octets")
        return

    run(args.target, dry_run=args.dry_run, force=args.force)


if __name__ == "__main__":
    main()
